class BatchProcessor {
  constructor(context, options = {}) {
    this.context = context;
    this.batchSize = validatePositiveInteger(options.batchSize, 500, 10000);
    this.maxRetries = validatePositiveInteger(options.maxRetries, 3, 10);
    this.retryDelayMs = validatePositiveInteger(options.retryDelayMs, 1000, 30000);
    this.processingTimeoutMs = validatePositiveInteger(options.processingTimeoutMs, 540000, 600000);
    this.processedCount = 0;
    this.errorCount = 0;
    this.startTime = Date.now();
    this._aborted = false;
  }

  isTimeRemaining() {
    const elapsed = Date.now() - this.startTime;
    const remaining = this.processingTimeoutMs - elapsed;
    // Keep a 30-second safety buffer
    return remaining > 30000;
  }

  abort() {
    this._aborted = true;
  }

  async processRecord(record, processingFn) {
    if (this._aborted) {
      throw new Error("Processing was aborted");
    }

    let lastError = null;

    for (let attempt = 1; attempt <= this.maxRetries; attempt++) {
      try {
        if (!this.isTimeRemaining()) {
          return {
            success: false,
            reason: "timeout_approaching",
            recordId: record.id
          };
        }

        const result = await processingFn(record);
        this.processedCount++;
        return { success: true, result, recordId: record.id };
      } catch (error) {
        lastError = error;
        this.context.log.warn(
          `Processing attempt ${attempt}/${this.maxRetries} failed for record`,
          {
            recordId: record.id,
            attempt,
            error: error.message
          }
        );

        if (attempt < this.maxRetries) {
          // Exponential backoff with jitter
          const baseDelay = this.retryDelayMs * Math.pow(2, attempt - 1);
          const jitter = Math.random() * baseDelay * 0.1;
          await this._delay(Math.min(baseDelay + jitter, 30000));
        }
      }
    }

    this.errorCount++;
    return {
      success: false,
      reason: "max_retries_exceeded",
      recordId: record.id,
      error: lastError ? lastError.message : "Unknown error"
    };
  }

  async processBatch(records, processingFn) {
    const results = [];
    const failures = [];

    for (const record of records) {
      if (!this.isTimeRemaining()) {
        this.context.log.warn("Approaching timeout, stopping batch processing", {
          processedInBatch: results.length,
          remainingInBatch: records.length - results.length - failures.length
        });
        break;
      }

      if (this._aborted) {
        this.context.log.warn("Processing aborted");
        break;
      }

      const result = await this.processRecord(record, processingFn);

      if (result.success) {
        results.push(result);
      } else {
        failures.push(result);
        if (result.reason === "timeout_approaching") {
          break;
        }
      }
    }

    return { results, failures };
  }

  getStats() {
    return {
      processedCount: this.processedCount,
      errorCount: this.errorCount,
      elapsedMs: Date.now() - this.startTime,
      aborted: this._aborted
    };
  }

  _delay(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

