const { sanitizeString } = require("./inputValidator");

function transformRecord(record) {
  // Validate input is an object
  if (!record || typeof record !== "object") {
    throw new Error("Invalid record: expected an object");
  }

  // Validate required fields exist
  if (!record.id || typeof record.id !== "string") {
    throw new Error("Invalid record: missing or invalid id");
  }

  // Sanitize and transform
  const transformed = {
    id: sanitizeString(record.id, 512),
    processedAt: new Date().toISOString(),
    originalTimestamp: record._ts ? new Date(record._ts * 1000).toISOString() : null,
    data: {}
  };

  // Safely transform data fields with validation
  if (record.data && typeof record.data === "object" && !Array.isArray(record.data)) {
    const allowedKeys = Object.keys(record.data).slice(0, 100); // Limit number of fields

    for (const key of allowedKeys) {
      const sanitizedKey = sanitizeString(key, 128);
      if (!sanitizedKey) continue;

      const value = record.data[key];

      if (typeof value === "string") {
        transformed.data[sanitizedKey] = sanitizeString(value, 4096);
      } else if (typeof value === "number" && isFinite(value)) {
        transformed.data[sanitizedKey] = value;
      } else if (typeof value === "boolean") {
        transformed.data[sanitizedKey] = value;
      } else if (value === null) {
        transformed.data[sanitizedKey] = null;
      }
      // Skip complex nested objects, functions, undefined, etc.
    }
  }

  // Compute aggregations if numeric data present
  const numericValues = Object.values(transformed.data).filter(
    (v) => typeof v === "number" && isFinite(v)
  );

  if (numericValues.length > 0) {
    transformed.aggregations = {
      sum: numericValues.reduce((a, b) => a + b, 0),
      avg: numericValues.reduce((a, b) => a + b, 0) / numericValues.length,
      min: Math.min(...numericValues),
      max: Math.max(...numericValues),
      count: numericValues.length
    };
  }

  transformed.status = "processed";
  return transformed;
}

