  const containerName = validateContainerName(process.env.COSMOS_CONTAINER_NAME);
  const batchSize = validateBatchSize(process.env.BATCH_SIZE);
  const maxRetries = validatePositiveInteger(process.env.MAX_RETRY_ATTEMPTS, 3, 10);
  const processingTimeoutMs = validatePositiveInteger(
    process.env.PROCESSING_TIMEOUT_MS,
    540000,
    600000
  );

